mapper.select:
SELECT
MAX(project.operation_datetime) AS operationDatetime,
project.project_number AS projectNumber,
COUNT(CASE WHEN problem_status = 1 THEN 1 END) AS unsolvedNumber,
COUNT(CASE WHEN problem_status = 2 THEN 1 END) AS solvedNumber,
COUNT(CASE WHEN problem_status = 3 THEN 1 END) AS recheckToBeRectifiedNumber,
COUNT(CASE WHEN problem_status = 4 THEN 1 END) AS notReinspectedNumber
FROM
village_construction_project_problem_total problem RIGHT JOIN village_construction_project_details AS project ON problem.project_number = project.project_number

    AND problem.problem_type = #{villageConstructionProjectProblemTotalSearchParam.problemType}


    AND problem.name like CONCAT('%',#{villageConstructionProjectProblemTotalSearchParam.name},'%')

WHERE 1=1

    AND project.area_id IN

        #{areaId}



    AND project.area_id = #{areaId}


    AND project.project_number = #{villageConstructionProjectProblemTotalSearchParam.projectNumber}


    AND project.supervision_credit_code = #{supervisionCompanyCreditCode}


    AND project.construction_credit_code = #{constructionCreditCode}


    AND project.project_name like CONCAT('%',#{villageConstructionProjectProblemTotalSearchParam.projectName},'%')


    AND project.construction_name = #{villageConstructionProjectProblemTotalSearchParam.constructionName}


    AND project.supervision_name = #{villageConstructionProjectProblemTotalSearchParam.supervisionName}


    AND project.add_datetime BETWEEN #{villageConstructionProjectProblemTotalSearchParam.startTime} AND #{villageConstructionProjectProblemTotalSearchParam.endTime}

GROUP BY
project.project_number

   SELECT
   MAX(project.operation_datetime) AS operationDatetime,
   project.project_number AS projectNumber,
   COUNT(CASE WHEN problem_type = 1 
   AND problem_status = #{param.solvedProblemStatus}
THEN 1 END) AS puzzlingProblem,
   COUNT(CASE WHEN problem_type = 2 
   AND problem_status = #{param.solvedProblemStatus}
THEN 1 END) AS onsiteProblem,
   COUNT(CASE WHEN problem_type = 3 
   AND problem_status = #{param.solvedProblemStatus}
THEN 1 END) AS remoteProblem
   FROM
   village_construction_project_problem_total AS problem RIGHT JOIN village_construction_project_details AS project
   ON problem.project_number = project.project_number
   WHERE 1=1

       AND project.area_id IN

           #{areaId}



       AND project.area_id = #{areaId}


       AND (
       project.project_name LIKE CONCAT('%',#{param.searchParam},'%')
       OR
       project.project_number LIKE CONCAT('%',#{param.searchParam},'%')
       )


       AND project.project_type = #{param.projectType}


       AND project.contract_number = #{param.contractNumber}


       AND project.supervision_credit_code = #{supervisionCompanyCreditCode}


       AND project.construction_credit_code = #{constructionCreditCode}


       AND project.construction_name = #{param.constructionName}


       AND project.supervision_name = #{param.supervisionName}


       AND project.add_datetime BETWEEN #{param.startDate} AND #{param.endDate}

   GROUP BY
   project.project_number
